// 从模板添加角色
async function addFromTemplate(template: PlatformRole) {
  if (isRoleExist(template.roleName)) {
    message.info('该角色已添加')
    return
  }

  saving.value = true
  try {
    const skills = template.skillTags
      ? template.skillTags.split(',').map(s => s.trim()).filter(Boolean)
      : []

    await request.post('/custom-roles', {
      name: template.roleName,
      category: template.category,
      description: template.description,
      commonSkills: skills,
    })
    message.success(`已添加角色: ${template.roleName}`)
    await loadData()
  } catch (err: any) {
    message.error(err?.response?.data?.message || '添加失败')
  } finally {
    saving.value = false
  }
}

// 编辑角色

/* 模板区域 */
.template-section {
  background: var(--color-bg-container);
  border: 1px solid var(--color-border-light);
  border-radius: 12px;
  padding: 20px;
  margin-bottom: 20px;
}

.template-hint {
  font-size: 13px;
  color: var(--color-text-tertiary);
  margin-bottom: 16px;
}

.template-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(180px, 1fr));
  gap: 12px;
}

.template-card {
  background: var(--color-bg-elevated);
  border: 1px solid var(--color-border-light);
  border-radius: 8px;
  padding: 12px;
  cursor: pointer;
  transition: all 0.2s;
  position: relative;
}

.template-card:hover:not(.disabled) {
  border-color: var(--color-primary);
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.08);
}

.template-card.disabled {
  opacity: 0.6;
  cursor: not-allowed;
}

.template-name {
  font-size: 14px;
  font-weight: 500;
  color: var(--color-text-primary);
  margin-bottom: 4px;
}

.template-category {
  font-size: 12px;
  color: var(--color-text-tertiary);
  margin-bottom: 4px;
}

.template-rate {
  font-size: 12px;
  color: var(--color-primary);
}

.template-add,
.template-added {
  position: absolute;
  top: 8px;
  right: 8px;
  font-size: 11px;
  padding: 2px 8px;
  border-radius: 10px;
}

.template-add {
  background: var(--color-primary-bg);
  color: var(--color-primary);
  opacity: 0;
  transition: opacity 0.2s;
}

.template-card:hover:not(.disabled) .template-add {
  opacity: 1;
}

.template-added {
  background: var(--color-success-bg);
  color: var(--color-success);
}

/* 已配置角色区域 */

